package com.eas.ui.user;
import com.eas.auth.LoginFrame; import com.eas.model.UserSession; import com.eas.service.AuditService; import com.eas.util.UITheme; import java.awt.*; import javax.swing.*;
public class UserDashboardFrame extends JFrame { public UserDashboardFrame(UserSession s){setTitle("GR 8 - Employee Attendance System | Employee Portal");setDefaultCloseOperation(EXIT_ON_CLOSE);setSize(1420,820);setLocationRelativeTo(null);setLayout(new BorderLayout());JPanel h=new JPanel(new BorderLayout());h.setBackground(UITheme.NAVY);h.setBorder(BorderFactory.createEmptyBorder(14,20,14,20));JLabel title=new JLabel("EMPLOYEE ATTENDANCE SYSTEM  |  EMPLOYEE PORTAL");title.setFont(new Font("SansSerif",Font.BOLD,18));title.setForeground(Color.WHITE);h.add(title,BorderLayout.WEST);JPanel account=new JPanel();account.setOpaque(false);JLabel name=new JLabel("Welcome, "+s.getFullName()+"   ");name.setForeground(Color.WHITE);JButton logout=UITheme.button("LOGOUT");account.add(name);account.add(logout);h.add(account,BorderLayout.EAST);add(h,BorderLayout.NORTH);JTabbedPane t=new JTabbedPane();t.addTab("Dashboard",new UserHomePanel(s));t.addTab("Time In/Out",new ClockPanel(s));t.addTab("My Attendance",new UserTablePanel(s,"My Attendance History","SELECT ar.id,ar.attendance_date,st.shift_name,ar.clock_in,ar.clock_out,ar.work_minutes,ar.late_minutes,ar.undertime_minutes,ar.overtime_minutes,ar.attendance_status,ar.remarks FROM employees e JOIN attendance_records ar ON e.id=ar.employee_id LEFT JOIN shift_templates st ON ar.shift_id=st.id WHERE e.user_id=? ORDER BY ar.attendance_date DESC","SELECT ar.id,ar.attendance_date,st.shift_name,ar.clock_in,ar.clock_out,ar.work_minutes,ar.late_minutes,ar.undertime_minutes,ar.overtime_minutes,ar.attendance_status,ar.remarks FROM employees e JOIN attendance_records ar ON e.id=ar.employee_id LEFT JOIN shift_templates st ON ar.shift_id=st.id WHERE e.user_id=? AND (ar.attendance_status LIKE ? OR ar.remarks LIKE ? OR CAST(ar.attendance_date AS CHAR) LIKE ?) ORDER BY ar.attendance_date DESC",true));t.addTab("Schedule",new UserTablePanel(s,"My Shift Schedule","SELECT ws.id,ws.schedule_date,st.shift_name,st.start_time,st.end_time,ws.schedule_status,ws.remarks FROM employees e JOIN work_schedules ws ON e.id=ws.employee_id JOIN shift_templates st ON ws.shift_id=st.id WHERE e.user_id=? ORDER BY ws.schedule_date DESC","SELECT ws.id,ws.schedule_date,st.shift_name,st.start_time,st.end_time,ws.schedule_status,ws.remarks FROM employees e JOIN work_schedules ws ON e.id=ws.employee_id JOIN shift_templates st ON ws.shift_id=st.id WHERE e.user_id=? AND (st.shift_name LIKE ? OR ws.schedule_status LIKE ? OR ws.remarks LIKE ?) ORDER BY ws.schedule_date DESC",true));t.addTab("Leave Types",new UserTablePanel(s,"Available Leave Types","SELECT lt.id,lt.leave_code,lt.leave_name,lt.annual_credits,lt.paid_status FROM leave_types lt JOIN users u ON u.id=? WHERE lt.status='ACTIVE'","SELECT lt.id,lt.leave_code,lt.leave_name,lt.annual_credits,lt.paid_status FROM leave_types lt JOIN users u ON u.id=? WHERE lt.status='ACTIVE' AND (lt.leave_code LIKE ? OR lt.leave_name LIKE ? OR lt.paid_status LIKE ?)",true));t.addTab("My Leaves",new MyLeavePanel(s));t.addTab("My Overtime",new MyOvertimePanel(s));t.addTab("Corrections",new MyCorrectionPanel(s));t.addTab("Announcements",new UserTablePanel(s,"Announcements","SELECT a.id,a.title,a.content,a.posted_at,a.valid_until FROM announcements a JOIN users u ON u.id=? WHERE a.status='ACTIVE' AND (a.target_audience='ALL' OR a.target_audience='EMPLOYEE') ORDER BY a.id DESC","SELECT a.id,a.title,a.content,a.posted_at,a.valid_until FROM announcements a JOIN users u ON u.id=? WHERE a.status='ACTIVE' AND (a.target_audience='ALL' OR a.target_audience='EMPLOYEE') AND (a.title LIKE ? OR a.content LIKE ? OR CAST(a.posted_at AS CHAR) LIKE ?) ORDER BY a.id DESC",true));t.addTab("Notifications",new NotificationPanel(s));t.addTab("Messages",new UserMessagePanel(s));t.addTab("Profile",new UserProfilePanel(s));add(t,BorderLayout.CENTER);logout.addActionListener(e->{AuditService.log(s.getId(),"LOGOUT","AUTHENTICATION","Employee logged out.");dispose();new LoginFrame().setVisible(true);});} }
